#include<cstdio>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=2e5+10;int a[N],t,n,k,cur=1,u[N],v[N],cmt,loc[N],l[N],r[N],cnt;
inline void ins(const int &x,const int &y){u[++cmt]=x;v[cmt]=y;}
inline void add(const int &L,const int &R){l[++cnt]=L;r[cnt]=R;}
inline void dfs(const int &l,const int &r)
{
	if(l>r)return;add(l,r);rep(l,r,i)--a[i];
	int ql=l;rep(l,r,i)if(!a[i]){dfs(ql,i-1);ql=i+1;} dfs(ql,r);	
}
int main()
{
	n=read();t=read();k=read()-1;
	rep(1,t,i)a[i]=read()-1;rep(1,t,i)ins(cur,cur+1),++cur;
	int ql=1;rep(1,n,i)if(!a[i]){dfs(ql,i-1);ql=i+1;}
	if(cnt>k)return puts("-1"),0;int p=1,qn=cnt;
	while(cnt<k&&p<=qn){while(l[p]<r[p]&&cnt<k)add(l[p],l[p]),++l[p];++p;}
	if(cnt<k)return puts("-1"),0;printf("%d\n",n);
	rep(1,cnt,i){ins(l[i],++cur);int t=r[i]-l[i];while(t--)ins(cur,cur+1),++cur;}
	rep(1,cmt,i)printf("%d %d\n",u[i],v[i]);return 0;
}
